const _wh = $('Webhook KP').first().json;
const p = _wh.body ?? _wh;

const DRIVE_PARENT_FOLDER_ID         = p.ses_drive_folder                || '1QSNGUZ9e7CAyeZNMJ3EpEUuyXTaSfTky';

const rateUSD = parseFloat(p.rate_usd) || 41.2;
const rateEUR = parseFloat(p.rate_eur) || 44.5;

const creditEnabled  = p.credit === 'yes';
const creditPageNum  = parseInt(p.ses_credit_page_num) || 2;
const vizPageNum     = parseInt(p.ses_viz_page_num)    || 3;
const hasCustomImage = !!(p.custom_image_base64);
const hasClientLogo  = !!(p.client_logo_base64);

// Вибір шаблону: спочатку по галузі, потім запасний
const SECTOR_TEMPLATE_MAP = {
  'Виробничі підприємства':               p.ses_tpl_sector1 || '',
  'Агропромисловий сектор':               p.ses_tpl_sector2 || '',
  'Будівельна та індустріальна група':    p.ses_tpl_sector3 || '',
  'Метал / машинобудування / обладнання': p.ses_tpl_sector4 || '',
  'Логістика / склади / торгові центри':  p.ses_tpl_sector5 || '',
  "Великі промислові об'єкти 1+ МВт":    p.ses_tpl_sector6 || '',
};
const sectorTpl = SECTOR_TEMPLATE_MAP[p.client_sector || ''];

let templateDocId = sectorTpl || '';
const delete_credit_page = !!sectorTpl && !creditEnabled;
const delete_viz_page    = !!sectorTpl && !hasCustomImage;

const managerName  = p.manager || '';
const managerPhone = p.manager_phone || '';
const managerEmail = p.manager_email || '';

const dcKW     = parseFloat(p.real_dc)     || 0;
const acKW     = parseFloat(p.real_ac)     || 0;
const panelQty = parseInt(p.panel_qty)     || 0;
const panelWatt= parseFloat(p.module_watt) || 0;
const panelModel = (p.module_type || '').replace(/^Фотоелектричні модулі\s*/i, '');

function invLine(model, qty) { return model && qty ? `${model} — ${qty} шт.` : ''; }
const inv1 = invLine(p.inverter_1_model, p.inverter_1_qty);
const inv2 = invLine(p.inverter_2_model, p.inverter_2_qty);
const inv3 = invLine(p.inverter_3_model, p.inverter_3_qty);
const invertersText = [inv1, inv2, inv3].filter(Boolean).join('\n');

const mountEntries = Array.isArray(p.mount_types) ? p.mount_types : [];
const mountText = mountEntries.map(e => `${e.type} (${e.qty} шт.)`).join(', ');

const currency   = p.currency    || 'USD';
const currSign   = currency === 'EUR' ? '€' : '$';
const rate       = currency === 'EUR' ? rateEUR : rateUSD;
const vatMode    = p.price_vat;
const vatLabel   = vatMode === 'with' ? 'з ПДВ' : 'без ПДВ';
const pricePerKW = parseFloat(p.price_per_kw) || 0;
const totalCurr  = +(dcKW * pricePerKW).toFixed(2);
const totalUAH   = Math.round(totalCurr * rate);

const tariffNow    = parseFloat(p.tariff_now)    || 0;
const creditRate   = parseFloat(p.credit_rate)   || 0;
const creditMonths = parseInt(p.credit_months)   || 60;
const yearlyKWhEst = Math.round(dcKW * 1100 * 0.80);
const yearlySavings = tariffNow > 0 ? yearlyKWhEst * tariffNow : 0;
const monthlySavingsUAH = tariffNow > 0 ? Math.round(yearlySavings / 12) : 0;

let monthlyPaymentUAH = 0;
let paybackStr = '—';
if (yearlySavings > 0 && totalUAH > 0) {
  if (creditEnabled && creditRate > 0) {
    const r = (creditRate / 100) / 12;
    monthlyPaymentUAH = Math.round(
      totalUAH * (r * Math.pow(1 + r, creditMonths)) / (Math.pow(1 + r, creditMonths) - 1)
    );
    const totalPaid = monthlyPaymentUAH * creditMonths;
    const py = totalPaid / yearlySavings;
    const pyInt = Math.floor(py);
    const pyMon = Math.round((py - pyInt) * 12);
    paybackStr = pyMon > 0 ? `${pyInt} р. ${pyMon} міс.` : `${pyInt} р.`;
  } else {
    const py = totalUAH / yearlySavings;
    const pyInt = Math.floor(py);
    const pyMon = Math.round((py - pyInt) * 12);
    paybackStr = pyMon > 0 ? `${pyInt} р. ${pyMon} міс.` : `${pyInt} р.`;
  }
}

const today = new Date().toLocaleDateString('uk-UA', { day: '2-digit', month: '2-digit', year: 'numeric' });
const safeName    = (p.project_name || 'Проект').replace(/\s+/g, '_');
const todayFile   = today.replace(/\./g, '-');
const fileName    = `КП_СЕС_${safeName}_${todayFile}.pdf`;
const docCopyName = `КП_СЕС_${p.project_name || 'Проект'}_${Date.now()}`;
const powerLabel  = `${dcKW.toFixed(0)} кВт`;

const templateVars = {
  '{{manager_name}}':      managerName,
  '{{manager_phone}}':     managerPhone,
  '{{manager_email}}':     managerEmail,
  '{{today_date}}':        today,
  '{{project_name}}':      p.project_name  || '',
  '{{region}}':            p.region        || '',
  '{{client_sector}}':     p.client_sector || '',
  '{{ses_type}}':          p.ses_type      || 'Дахова',
  '{{panel_model}}':       panelModel,
  '{{panel_qty}}':         String(panelQty),
  '{{panel_watt}}':        String(Math.round(panelWatt)),
  '{{dc_kw}}':             dcKW.toFixed(1),
  '{{ac_kw}}':             acKW.toFixed(0),
  '{{inverter_1}}':        inv1,
  '{{inverter_2}}':        inv2,
  '{{inverter_3}}':        inv3,
  '{{inverters_text}}':    invertersText,
  '{{mount_types}}':       mountText,
  '{{material_type}}':     p.material_type     || '',
  '{{power_regulation}}':  p.power_regulation  || '',
  '{{monitoring_device}}': p.monitoring_device || '',
  '{{currency}}':          currSign,
  '{{vat_label}}':         vatLabel,
  '{{price_per_kw}}':      String(pricePerKW),
  '{{total_price}}':       Math.round(totalCurr).toLocaleString('uk-UA'),
  '{{total_uah}}':         totalUAH.toLocaleString('uk-UA'),
  '{{tariff_now}}':        tariffNow ? `${tariffNow.toFixed(2)} грн/кВт·год` : '—',
  '{{yearly_gen}}':        '',
  '{{payback}}':           paybackStr,
  '{{total_profit}}':      yearlySavings > 0 ? `${Math.round(yearlySavings / 1000)} тис. грн/рік` : '—',
  '{{credit_enabled}}':    creditEnabled ? 'Так' : 'Ні',
  '{{credit_months}}':     creditEnabled ? String(creditMonths) : '',
  '{{credit_rate}}':       creditEnabled ? `${creditRate}%` : '',
  '{{monthly_payment}}':   creditEnabled && monthlyPaymentUAH ? `${monthlyPaymentUAH.toLocaleString('uk-UA')} грн/міс.` : '',
  '{{year_chart_url}}':    '',
  '{{day_chart_url}}':     '',
  '{{custom_image}}':      '',
  '{{client_logo}}':       '',
};

return [{
  json: {
    templateDocId,
    driveFolderId:       DRIVE_PARENT_FOLDER_ID,
    doc_copy_name:       docCopyName,
    file_name:           fileName,
    template_vars:       templateVars,
    chat_id:             p.chat_id,
    manager:             managerName,
    power_label:         powerLabel,
    project_name:        p.project_name  || '',
    region:              p.region        || '',
    currency_sign:       currSign,
    total_display:       `${Math.round(totalCurr).toLocaleString('uk-UA')} ${currSign}`,
    dc_kw:               dcKW,
    tariff_now:          tariffNow,
    credit_enabled:      creditEnabled,
    credit_months:       creditMonths,
    monthly_payment_uah: monthlyPaymentUAH,
    monthly_savings_uah: monthlySavingsUAH,
    total_usd:           totalCurr,
    rate_usd:            rate,
    has_custom_image:    hasCustomImage,
    has_client_logo:     hasClientLogo,
    custom_image_base64: p.custom_image_base64 || null,
    custom_image_mime:   p.custom_image_mime   || null,
    client_logo_base64:  p.client_logo_base64  || null,
    client_logo_mime:    p.client_logo_mime    || null,
    delete_credit_page:  delete_credit_page,
    delete_viz_page:     delete_viz_page,
    credit_page_num:     creditPageNum,
    viz_page_num:        vizPageNum,
  }
}];

const MONTHLY_COEF = {
  'Чернігівська область':     [22, 33, 65, 98, 118, 120, 122, 113, 85, 50, 24, 17],
  'Сумська область':          [23, 34, 66, 99, 119, 121, 123, 114, 86, 51, 25, 18],
  'Житомирська область':      [24, 35, 67, 100, 120, 122, 124, 115, 87, 52, 25, 18],
  'Волинська область':        [24, 36, 67, 100, 119, 120, 122, 112, 85, 51, 25, 17],
  'Рівненська область':       [24, 36, 68, 101, 120, 121, 123, 113, 86, 52, 25, 18],
  'Львівська область':        [26, 38, 72, 106, 123, 124, 127, 118, 90, 56, 27, 19],
  'Закарпатська область':     [30, 44, 80, 113, 130, 131, 135, 126, 98, 62, 31, 22],
  'Івано-Франківська область':[27, 40, 74, 107, 124, 125, 128, 119, 91, 57, 28, 20],
  'Тернопільська область':    [26, 38, 71, 105, 122, 123, 126, 117, 89, 55, 26, 18],
  'Хмельницька область':      [26, 38, 71, 105, 122, 123, 126, 117, 89, 55, 26, 18],
  'Вінницька область':        [27, 40, 74, 108, 126, 127, 130, 120, 92, 57, 27, 19],
  'Чернівецька область':      [28, 42, 78, 112, 129, 130, 134, 125, 96, 60, 29, 21],
  'м. Київ':                  [25, 37, 71, 105, 124, 126, 128, 118, 89, 53, 25, 18],
  'Київська область':         [25, 37, 70, 104, 123, 125, 127, 117, 88, 52, 25, 17],
  'Черкаська область':        [28, 42, 78, 112, 131, 133, 135, 125, 95, 58, 27, 19],
  'Полтавська область':       [29, 43, 79, 114, 133, 135, 137, 127, 97, 60, 28, 20],
  'Кіровоградська область':   [31, 47, 85, 119, 138, 140, 143, 133, 103, 64, 30, 22],
  'Харківська область':       [28, 43, 80, 114, 133, 135, 138, 128, 97, 59, 27, 19],
  'Дніпропетровська область': [32, 49, 87, 122, 141, 143, 146, 136, 105, 66, 31, 22],
  'Донецька область':         [30, 46, 84, 118, 137, 139, 142, 132, 101, 63, 30, 21],
  'Запорізька область':       [35, 53, 95, 131, 150, 152, 156, 145, 113, 72, 34, 25],
  'Луганська область':        [29, 44, 81, 115, 134, 136, 139, 129, 98, 60, 28, 20],
  'Одеська область':          [38, 57, 100, 137, 156, 158, 163, 151, 118, 76, 37, 27],
  'Миколаївська область':     [36, 55, 98, 134, 153, 155, 160, 148, 115, 73, 35, 26],
  'Херсонська область':       [37, 56, 100, 136, 155, 157, 162, 150, 117, 75, 36, 26],
  'default':                  [28, 42, 77, 111, 130, 132, 134, 124, 95, 59, 28, 19]
};

const MONTHS_UK = ['Січ', 'Лют', 'Бер', 'Квіт', 'Трав', 'Черв', 'Лип', 'Серп', 'Вер', 'Жовт', 'Лис', 'Груд'];

const DAILY_HOURLY_PROFILE = [
  0, 0, 0, 0, 0, 0.03,
  0.08, 0.18, 0.38, 0.58, 0.75, 0.88,
  0.97, 1.00, 0.97, 0.88, 0.75, 0.58,
  0.35, 0.15, 0.05, 0.01, 0, 0
];

const calc = $('SES: Calculate').first().json;
const dcKW      = parseFloat(calc.dc_kw)  || 0;
const region    = calc.region || 'default';
const tariffNow = parseFloat(calc.tariff_now) || 0;

const coefs = MONTHLY_COEF[region] || MONTHLY_COEF['default'];
const monthlyKWh = coefs.map(c => Math.round(c * dcKW));
const yearlyKWh  = monthlyKWh.reduce((s, v) => s + v, 0);
const yearlyMWh  = Math.round(yearlyKWh / 100) / 10;
const peakIdx    = monthlyKWh.indexOf(Math.max(...monthlyKWh));
const peakKWh    = monthlyKWh[peakIdx];

const daysInPeakMonth = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31][peakIdx];
const dailyAvgKWh     = peakKWh / daysInPeakMonth;
const dailyHourlyKWh  = DAILY_HOURLY_PROFILE.map(factor => +(factor * dailyAvgKWh).toFixed(1));
const hourLabels = Array.from({ length: 24 }, (_, i) => `${i}:00`);

const yearChartConfig = {
  type: 'bar',
  data: {
    labels: MONTHS_UK,
    datasets: [{
      label: 'Генерація, кВт·год',
      data: monthlyKWh,
      backgroundColor: monthlyKWh.map((_, i) => i === peakIdx ? '#FFC400' : '#4A90D9'),
      borderRadius: 6
    }]
  },
  options: {
    plugins: {
      legend: { display: false },
      title: { display: true, text: `Річна генерація СЕС ${dcKW.toFixed(0)} кВт · ${region}`, font: { size: 14 } },
      datalabels: { anchor: 'end', align: 'top', font: { size: 10 }, formatter: (v) => v >= 1000 ? `${(v/1000).toFixed(1)}МВт` : `${v}` }
    },
    scales: {
      y: { beginAtZero: true, title: { display: true, text: 'кВт·год' }, grid: { color: '#f0f0f0' } },
      x: { grid: { display: false } }
    }
  }
};

const dayChartConfig = {
  type: 'line',
  data: {
    labels: hourLabels,
    datasets: [{
      label: `Генерація (${MONTHS_UK[peakIdx]}, кВт·год/год)`,
      data: dailyHourlyKWh,
      borderColor: '#FFC400',
      backgroundColor: 'rgba(255,196,0,0.15)',
      borderWidth: 2.5,
      pointRadius: 3,
      fill: true,
      tension: 0.4
    }]
  },
  options: {
    plugins: {
      legend: { display: false },
      title: { display: true, text: `Денна генерація (${MONTHS_UK[peakIdx]}, середній день) · СЕС ${dcKW.toFixed(0)} кВт`, font: { size: 14 } }
    },
    scales: {
      y: { beginAtZero: true, title: { display: true, text: 'кВт·год/год' }, grid: { color: '#f0f0f0' } },
      x: { grid: { display: false }, ticks: { maxTicksLimit: 12 } }
    }
  }
};

function toChartUrl(config, width, height) {
  return `https://quickchart.io/chart?w=${width}&h=${height}&bkg=white&c=${encodeURIComponent(JSON.stringify(config))}`;
}

const yearChartUrl = toChartUrl(yearChartConfig, 800, 380);
const dayChartUrl  = toChartUrl(dayChartConfig,  800, 380);

const selfConsumptionRatio = 0.80;
const yearlyEconomyUAH = tariffNow > 0
  ? Math.round(yearlyKWh * selfConsumptionRatio * tariffNow)
  : Math.round(calc.monthly_savings_uah * 12) || 0;

const totalUAH2 = (parseFloat(calc.total_usd) || 0) * (parseFloat(calc.rate_usd) || 41.2);
let paybackStr = '—';
if (yearlyEconomyUAH > 0 && totalUAH2 > 0) {
  const py    = totalUAH2 / yearlyEconomyUAH;
  const pyInt = Math.floor(py);
  const pyMon = Math.round((py - pyInt) * 12);
  paybackStr  = pyMon > 0 ? `${pyInt} р. ${pyMon} міс.` : `${pyInt} р.`;
}

return [{
  json: {
    ...calc,
    year_chart_url: yearChartUrl,
    day_chart_url:  dayChartUrl,
    monthly_kwh:    monthlyKWh,
    yearly_kwh:     yearlyKWh,
    yearly_mwh:     yearlyMWh,
    peak_month:     MONTHS_UK[peakIdx],
    yearly_economy: yearlyEconomyUAH,
    payback_str_regional: paybackStr,
    template_vars: {
      ...calc.template_vars,
      '{{yearly_gen}}':   `${yearlyMWh} МВт·год`,
      '{{payback}}':      paybackStr,
      '{{tariff_now}}':   tariffNow ? `${tariffNow.toFixed(2)} грн/кВт·год` : (calc.template_vars?.['{{tariff_now}}'] || ''),
      '{{total_profit}}': `${Math.round(yearlyEconomyUAH / 1000)} тис. грн/рік`,
      '{{year_chart_url}}': yearChartUrl,
      '{{day_chart_url}}':  dayChartUrl
    }
  }
}];

const data = $('SES: Charts').first().json;

const result = { json: { ...data }, binary: {} };

if (data.custom_image_base64) {
  const mime = data.custom_image_mime || 'image/jpeg';
  const ext  = mime.split('/')[1] || 'jpg';
  const fileName = `viz_${data.project_name || 'ses'}_${Date.now()}.${ext}`;
  result.json.image_file_name = fileName;
  result.json.image_mime      = mime;
  result.binary.customImage   = { data: data.custom_image_base64, mimeType: mime, fileName };
}

if (data.client_logo_base64) {
  const mime = data.client_logo_mime || 'image/png';
  const ext  = mime.split('/')[1] || 'png';
  const logoName = `logo_${data.project_name || 'ses'}_${Date.now()}.${ext}`;
  result.json.logo_file_name = logoName;
  result.json.logo_mime      = mime;
  result.binary.clientLogo   = { data: data.client_logo_base64, mimeType: mime, fileName: logoName };
}

return [result];

const calc = $('SES: Charts').first().json;

let customImageDriveUrl = null;
let clientLogoDriveUrl  = null;

try {
  const imageItems = $('SES: Upload Custom Image').all();
  if (imageItems.length > 0) {
    const id = imageItems[0].json.id;
    customImageDriveUrl = `https://drive.google.com/uc?export=view&id=${id}`;
  }
} catch (e) {}

try {
  const logoItems = $('SES: Upload Client Logo').all();
  if (logoItems.length > 0) {
    const id = logoItems[0].json.id;
    clientLogoDriveUrl = `https://drive.google.com/uc?export=view&id=${id}`;
  }
} catch (e) {}

return [{
  json: {
    ...calc,
    custom_image_drive_url: customImageDriveUrl,
    client_logo_drive_url:  clientLogoDriveUrl,
    template_vars: {
      ...calc.template_vars,
      '{{custom_image}}': customImageDriveUrl || '',
      '{{client_logo}}':  clientLogoDriveUrl  || ''
    }
  }
}];

const tab0Content = $json.tabs?.[0]?.documentTab?.body?.content || [];
const bodyContent = $json.body?.content || [];
const content = tab0Content.length > 0 ? tab0Content : bodyContent;

const calc  = $('SES: Після зображення').first().json;
const docId = $('SES: Копіювати шаблон').first().json.id;

const rangesToDelete = [];

// Видалити «Вкладка 1»
let startIndex = null;
let endIndex   = null;
for (let i = 0; i < content.length; i++) {
  const el = content[i];
  if (!el.paragraph || !el.paragraph.elements) continue;
  const text = el.paragraph.elements
    .map(e => (e.textRun?.content || '').trim().toLowerCase())
    .join('');
  if (text === 'вкладка 1') {
    startIndex = el.startIndex;
  } else if (startIndex !== null && text !== '') {
    endIndex = el.startIndex;
    break;
  }
}
if (startIndex !== null && endIndex !== null) {
  rangesToDelete.push({ startIndex, endIndex: endIndex - 1 });
}

const deleteRequests = rangesToDelete.map(r => ({
  deleteContentRange: { range: { startIndex: r.startIndex, endIndex: r.endIndex } }
}));

return [{ json: { docId, deleteRequests, ...calc } }];

const calc  = $('SES: Після зображення').first().json;
const docId = $('SES: Копіювати шаблон').first().json.id;
const vars  = calc.template_vars;

const requests = Object.entries(vars).map(([tag, value]) => ({
  replaceAllText: {
    containsText: { text: tag, matchCase: true },
    replaceText:  String(value ?? '')
  }
}));

return [{
  json: {
    docId,
    requests,
    chat_id:       calc.chat_id,
    file_name:     calc.file_name,
    project_name:  calc.project_name,
    power_label:   calc.power_label,
    total_display: calc.total_display,
    currency_sign: calc.currency_sign,
    driveFolderId: calc.driveFolderId
  }
}];

const docData = $json;
const calc    = $('SES: Підготовка Docs').first().json;
const docId   = calc.docId;

const content = docData.tabs?.[0]?.documentTab?.body?.content || docData.body?.content || [];

const requests = [];

for (const el of content) {
  if (!el.table) continue;

  const isCostTable = el.table.tableRows.some(row => {
    const firstCell = (row.tableCells[0]?.content || [])
      .flatMap(p => (p.paragraph?.elements || []))
      .map(e => e.textRun?.content || '')
      .join('')
      .trim();
    return firstCell.includes('ОБЛАДНАННЯ');
  });
  if (!isCostTable) continue;

  const tableStartIndex = el.startIndex;
  const emptyRowIndices = [];

  el.table.tableRows.forEach((row, rowIndex) => {
    const allEmpty = row.tableCells.every(cell => {
      const cellText = (cell.content || [])
        .flatMap(p => (p.paragraph?.elements || []))
        .map(e => e.textRun?.content || '')
        .join('')
        .trim();
      return cellText === '';
    });
    if (allEmpty) emptyRowIndices.push(rowIndex);
  });

  for (let i = emptyRowIndices.length - 1; i >= 0; i--) {
    requests.push({
      deleteTableRow: {
        tableCellLocation: {
          tableStartLocation: { index: tableStartIndex },
          rowIndex: emptyRowIndices[i],
          columnIndex: 0
        }
      }
    });
  }
}

return [{ json: { docId, ...calc, requests } }];

const _wh = $('Webhook KP').first().json;
const p = _wh.body ?? _wh;

const DRIVE_FOLDER_ID = p.uze_drive_folder || p.ses_drive_folder || '1QSNGUZ9e7CAyeZNMJ3EpEUuyXTaSfTky';

if (!p.template_id) {
  throw new Error(`UZE webhook: відсутній template_id. Отримано: ${JSON.stringify(Object.keys(p))}`);
}

if (!p.template_vars || typeof p.template_vars !== 'object') {
  throw new Error('UZE webhook: відсутній або некоректний template_vars');
}

return [{
  json: {
    templateDocId:  p.template_id,
    driveFolderId:  DRIVE_FOLDER_ID,
    doc_copy_name:  p.doc_copy_name || `КП_УЗЕ_${p.project_name || 'Проект'}_${Date.now()}`,
    file_name:      p.file_name     || `КП_УЗЕ_${(p.project_name || 'Проект').replace(/\s+/g, '_')}.pdf`,
    template_vars:  p.template_vars,
    tail_pages:     parseInt(p.tail_pages) || 5,
    chat_id:        p.chat_id,
    project_name:   p.project_name  || '',
    manager:        p.manager       || '',
    uze_model:      p.uze_model     || '',
    uze_qty:        p.uze_qty       || 1,
    currency_sign:  p.currency === 'EUR' ? '€' : '$'
  }
}];

const tab0Content = $json.tabs?.[0]?.documentTab?.body?.content || [];
const bodyContent = $json.body?.content || [];
const content = tab0Content.length > 0 ? tab0Content : bodyContent;

const prep  = $('UZE: Підготовка').first().json;
const docId = $('UZE: Копіювати шаблон').first().json.id;

let startIndex = null;
let endIndex   = null;

for (let i = 0; i < content.length; i++) {
  const el = content[i];
  if (!el.paragraph || !el.paragraph.elements) continue;
  const text = el.paragraph.elements
    .map(e => (e.textRun?.content || '').trim().toLowerCase())
    .join('');
  if (text === 'вкладка 1') {
    startIndex = el.startIndex;
  } else if (startIndex !== null && text !== '') {
    endIndex = el.startIndex;
    break;
  }
}

const deleteRequests = (startIndex !== null && endIndex !== null)
  ? [{ deleteContentRange: { range: { startIndex, endIndex: endIndex - 1 } } }]
  : [];

return [{ json: { docId, deleteRequests, ...prep } }];

const prep  = $('UZE: Підготовка').first().json;
const docId = $('UZE: Копіювати шаблон').first().json.id;
const vars  = prep.template_vars;

const requests = Object.entries(vars).map(([tag, value]) => ({
  replaceAllText: {
    containsText: { text: tag, matchCase: true },
    replaceText:  String(value ?? '')
  }
}));

return [{
  json: {
    docId,
    requests,
    chat_id:       prep.chat_id,
    file_name:     prep.file_name,
    project_name:  prep.project_name,
    uze_model:     prep.uze_model,
    uze_qty:       prep.uze_qty,
    driveFolderId: prep.driveFolderId,
    currency_sign: prep.currency_sign
  }
}];

const docData = $json;
const prep    = $('UZE: Підготовка Docs').first().json;
const docId   = prep.docId;

const content = docData.tabs?.[0]?.documentTab?.body?.content || docData.body?.content || [];

const requests = [];

for (const el of content) {
  if (!el.table) continue;

  const isCostTable = el.table.tableRows.some(row => {
    const firstCell = (row.tableCells[0]?.content || [])
      .flatMap(p => (p.paragraph?.elements || []))
      .map(e => e.textRun?.content || '')
      .join('')
      .trim();
    return firstCell.match(/обладнання|ОБЛАДНАННЯ|специфікація|СПЕЦИФІКАЦІЯ/i);
  });
  if (!isCostTable) continue;

  const tableStartIndex = el.startIndex;
  const emptyRowIndices = [];

  el.table.tableRows.forEach((row, rowIndex) => {
    const allEmpty = row.tableCells.every(cell => {
      const cellText = (cell.content || [])
        .flatMap(p => (p.paragraph?.elements || []))
        .map(e => e.textRun?.content || '')
        .join('')
        .trim();
      return cellText === '';
    });
    if (allEmpty) emptyRowIndices.push(rowIndex);
  });

  for (let i = emptyRowIndices.length - 1; i >= 0; i--) {
    requests.push({
      deleteTableRow: {
        tableCellLocation: {
          tableStartLocation: { index: tableStartIndex },
          rowIndex: emptyRowIndices[i],
          columnIndex: 0
        }
      }
    });
  }
}

return [{ json: { docId, ...prep, requests } }];

const calc = $('SES: Calculate').first().json;
const pages = [];
if (calc.delete_credit_page) pages.push(calc.credit_page_num || 2);
if (calc.delete_viz_page)    pages.push(calc.viz_page_num    || 3);
pages.sort((a, b) => a - b);

return [{
  json: {
    upload_url: $json.url,
    pages_str:  pages.join(',')
  }
}];
